（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00576', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'essay', '我國籍人甲於 2000 年在其香港居所之律師事務所書立遺囑，訂明甲願
將死後全部位於臺灣之不動產贈與香港籍人乙。遺囑未明定應適用之法
律。2008 年甲在香港過世，甲之法定繼承人於 2012 年向我國法院提起
訴訟，主張該遺囑不符法定要式為無效。請問：
關於本案應如何定性？（10 分）
關於本案應如何適用準據法？（10分）是否有反致之可能？（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00577', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '《國際法院規約》第38條規定國際法的淵源，下列敘述何者錯誤？', '["第38條並未明示法源之間的位階", "司法判決可作為確定法律之資料", "習慣係作為通例之證明而經接受為法律者", "公允及善良原則係該條所稱「一般法律原則」之重要例子"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00578', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '依維也納條約法公約，關於條約之終止，下列敘述何者正確？', '["條約中若無條款規定終止問題，原則上條約無限期有效", "當事國一方違反雙邊條約時，他方即可終止條約", "締約之一方，不得因實施條約所必不可少之標的物永久消失或毀壞以致履行不能為由，終止條約", "二國斷絕外交或領事關係，所有條約當然終止"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00579', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '參考瑞士中立化之實踐，下列敘述何者正確？', '["一國得單方面宣告中立化而成為中立化國家", "有關大國訂定條約對一國中立化地位給予集體保證", "須經由聯合國大會通過，一國才能取得中立化地位", "一個中立國有不參加任何國際組織的義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00580', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '國際法中的「先占」概念已成為領土取得的重要要件。下列敘述何者錯誤？', '["國際法中之「先占」概念來自國內私法之「時效取得」概念", "國家發現無主地後，仍需有效控制始能取得領土主權", "實際上持續並和平展現國家功能係先占的重要要件之一", "「發現」給予國家期待權可以在合理期間內完成先占"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00581', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '1951年「難民地位公約」所列符合難民資格的畏懼受迫害之因素，不包括下列何者？', '["國籍", "戰爭", "屬於某一社會團體", "具有某種政治見解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00582', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '依據聯合國海洋法公約，下列敘述何者正確？', '["島嶼是四面環水並在高潮時高於水平面的自然形成的陸地區域，故人造島無法擁有領海", "若低潮高地全部與大陸或島嶼的距離超過領海的寬度，則該高地可以有其自己的領海", "所有國家的船舶均享有無害通過他國領海的權利，沿海國不得制定關於無害通過的法律或規章", "沿海國應在通過領海的外國船舶上行使刑事管轄權，以逮捕與在該船舶通過期間船上所犯任何 罪行有關的任何人，或進行與該罪行有關的任何調查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00583', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-cf527099', 'sub-diplomatic-d3cf880d-07', NULL, 'single_choice', '關於「國籍」，下列敘述何者錯誤？', '["一國得對具有該國國籍之人民行使屬人管轄權", "各國國內法關於取得國籍之方式有相同之規定", "國民得請求其國家保護，並得依國際法規範享有與國籍相關的利益", "一國原則上得依其國內法規定決定何人為其國民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "705e62bb3941", "answer_pdf_sha1": "4633c06a9e7e", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際法(含國際公法與國際私法)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
